// Formats the forensic debate into a readable chat message with verdict badge, metrics table, and the debate chain.

const reportData = $input.first().json;
const finalVerdict = reportData.finalVerdict;
const agentDebate = reportData.debate;
const textMetrics = reportData.metrics;
const metricSignals = reportData.metricSignals;

let verdictBadge = "";
if (finalVerdict.classification === "human") verdictBadge = "🙎🏻 **Verdict: Human-Written**";
else if (finalVerdict.classification === "ai") verdictBadge = "🤖 **Verdict: AI-Generated**";
else verdictBadge = "🦾 **Verdict: AI-Augmented (Hybrid)**";

const confidencePercent = Math.round(finalVerdict.confidence * 100);
const filledBarBlocks = Math.floor(confidencePercent / 10);
const emptyBarBlocks = 10 - filledBarBlocks;
const confidenceBar = "█".repeat(filledBarBlocks) + "░".repeat(emptyBarBlocks);

let chatMessage = `${verdictBadge}\n`;
chatMessage += `**Confidence:** ${confidenceBar} ${confidencePercent}%\n\n`;

chatMessage += `**📊 Stylometric Metrics:**\n`;
chatMessage += `Burstiness: ${textMetrics.burstiness} ${textMetrics.burstiness < 0.3 ? '🟥 AI' : '🟩 Human'}\n`;
chatMessage += `Vocabulary Diversity: ${textMetrics.typeTokenRatio} ${textMetrics.typeTokenRatio < 0.4 ? '🟥 AI' : '🟩 Human'}\n`;
chatMessage += `Hapax Rate: ${textMetrics.hapaxRate} ${textMetrics.hapaxRate < 0.4 ? '🟥 AI' : '🟩 Human'}\n`;
chatMessage += `Repetition: ${textMetrics.repetitionScore} ${textMetrics.repetitionScore > 0.15 ? '🟥 AI' : '🟩 Human'}\n`;
chatMessage += `Transition Density: ${textMetrics.transitionDensity} ${textMetrics.transitionDensity > 0.015 ? '🟥 AI' : '🟩 Human'}\n\n`;

chatMessage += `---\n\n`;

chatMessage += `**🔎 Agent 1 (Gut Check):** ${agentDebate.scanner.impression.toUpperCase()} (${Math.round(agentDebate.scanner.confidence * 100)}%)\n`;
const scannerReasoningText = agentDebate.scanner.gut_reasoning || "";

const maxScannerLength = 200;
chatMessage += `*"${scannerReasoningText.length > maxScannerLength ? scannerReasoningText.substring(0, maxScannerLength) + '...' : scannerReasoningText}"*\n\n`;

chatMessage += `**🔬 Agent 2 (Data):** ${agentDebate.analyst.classification.toUpperCase()} (${Math.round(agentDebate.analyst.confidence * 100)}%)\n`;
const analystReportText = agentDebate.analyst.forensic_report || "";

const maxAnalystLength = 200;
chatMessage += `*"${analystReportText.length > maxAnalystLength ? analystReportText.substring(0, maxAnalystLength) + '...' : analystReportText}"*\n\n`;

chatMessage += `**😈 Agent 3 (Critic):** ${agentDebate.devilsAdvocate.counter_classification.toUpperCase()} (${Math.round(agentDebate.devilsAdvocate.confidence * 100)}%)\n`;
const counterArgumentText = agentDebate.devilsAdvocate.counter_argument || "";

const maxDevilLength = 200;
chatMessage += `*"${counterArgumentText.length > maxDevilLength ? counterArgumentText.substring(0, maxDevilLength) + '...' : counterArgumentText}"*\n`;

const biggestFlawText = agentDebate.devilsAdvocate.strongest_weakness || "";
if (biggestFlawText) {
  chatMessage += `**Flaw Found:** ${biggestFlawText}\n`;
}

return [{
  json: {
    output: chatMessage,
  }
}];

// Weighs the full debate chain and raw metrics to produce the final classification, with short-text adjustments and AI fingerprint boosting.

const analystPackageOutput = $('Package Analyst Output').first().json;
const devilsAdvocateRawOutput = $input.first().json.output || $input.first().json.text || "";

let parsedDevilsAdvocateVerdict = {};

try {
  let cleanedDevilOutput = devilsAdvocateRawOutput.trim();
  if (cleanedDevilOutput.startsWith("```json")) cleanedDevilOutput = cleanedDevilOutput.slice(7);
  if (cleanedDevilOutput.startsWith("```")) cleanedDevilOutput = cleanedDevilOutput.slice(3);
  if (cleanedDevilOutput.endsWith("```")) cleanedDevilOutput = cleanedDevilOutput.slice(0, -3);
  parsedDevilsAdvocateVerdict = JSON.parse(cleanedDevilOutput.trim());
} catch (parseError) {
  parsedDevilsAdvocateVerdict = {
    counter_classification: "unknown",
    confidence: 0,
    counter_argument: "Devil's Advocate failed: " + parseError.message,
    strongest_weakness: "N/A",
  };
}

const scannerVerdict = analystPackageOutput.scannerVerdict;
const analystVerdict = analystPackageOutput.analystVerdict;
const devilsAdvocateVerdict = parsedDevilsAdvocateVerdict;
const textMetrics = analystPackageOutput.metrics;

let aiSignalCount = 0;
let humanSignalCount = 0;

if (textMetrics.burstiness < 0.3) aiSignalCount += 1;
else humanSignalCount += 1;

if (textMetrics.typeTokenRatio < 0.4) aiSignalCount += 1;
else humanSignalCount += 1;

if (textMetrics.hapaxRate < 0.4) aiSignalCount += 1;
else humanSignalCount += 1;

if (textMetrics.repetitionScore > 0.15) aiSignalCount += 1;
else humanSignalCount += 1;

if (textMetrics.transitionDensity > 0.015) aiSignalCount += 1;
else humanSignalCount += 1;

if (textMetrics.aiFingerprintCount >= 8) aiSignalCount += 4;
else if (textMetrics.aiFingerprintCount >= 5) aiSignalCount += 2;
else if (textMetrics.aiFingerprintCount >= 3) aiSignalCount += 1;

if (textMetrics.transitionDensity >= 0.05) aiSignalCount += 3;
else if (textMetrics.transitionDensity >= 0.03) aiSignalCount += 2;

if (textMetrics.totalWords < 150) {
  if (textMetrics.burstiness < 0.2) aiSignalCount += 2;
  if (textMetrics.transitionDensity > 0.02) aiSignalCount += 2;
  if (textMetrics.aiFingerprintCount >= 3) aiSignalCount += 1;
}

const totalSignalCount = aiSignalCount + humanSignalCount;

const isScannerValid = scannerVerdict.impression && scannerVerdict.impression !== "unknown";
const isAnalystValid = analystVerdict.classification && analystVerdict.classification !== "unknown";
const isDevilValid = devilsAdvocateVerdict.counter_classification && devilsAdvocateVerdict.counter_classification !== "unknown";

let analystWeight = 0.35;
let scannerWeight = 0.15;
let devilsAdvocateWeight = 0.15;
let metricsWeight = 0.35;

if (!isScannerValid) {
  metricsWeight += scannerWeight;
  scannerWeight = 0;
}

const metricAiRatio = totalSignalCount > 0 ? aiSignalCount / totalSignalCount : 0.5;

if (metricAiRatio >= 0.70 || metricAiRatio <= 0.30) {
  metricsWeight += 0.10;
  devilsAdvocateWeight -= 0.10;
}

function convertClassificationToScore(classification) {
  if (classification === "ai") return 1.0;
  if (classification === "ai-augmented") return 0.5;
  if (classification === "human") return 0.0;
  return 0.5;
}

const scannerNumericScore = isScannerValid
  ? convertClassificationToScore(scannerVerdict.impression) * scannerVerdict.confidence
  : 0;

const analystNumericScore = isAnalystValid
  ? convertClassificationToScore(analystVerdict.classification) * analystVerdict.confidence
  : 0.5;

const devilsAdvocateNumericScore = isDevilValid
  ? convertClassificationToScore(devilsAdvocateVerdict.counter_classification) * devilsAdvocateVerdict.confidence
  : 0.5;

const metricsNumericScore = totalSignalCount > 0 ? aiSignalCount / totalSignalCount : 0.5;

const combinedWeightedScore =
  (analystNumericScore * analystWeight) +
  (scannerNumericScore * scannerWeight) +
  (devilsAdvocateNumericScore * devilsAdvocateWeight) +
  (metricsNumericScore * metricsWeight);

let finalClassification = "ai-augmented";
let finalConfidenceScore = 0.5;

if (combinedWeightedScore >= 0.60) {
  finalClassification = "ai";
  finalConfidenceScore = Math.min(0.95, 0.5 + combinedWeightedScore);
} else if (combinedWeightedScore <= 0.35) {
  finalClassification = "human";
  finalConfidenceScore = Math.min(0.95, 0.5 + (1 - combinedWeightedScore));
} else {
  finalClassification = "ai-augmented";
  finalConfidenceScore = 0.5 + Math.abs(combinedWeightedScore - 0.5);
}

finalConfidenceScore = Math.round(finalConfidenceScore * 100) / 100;

const failedAgentNames = [];
if (!isScannerValid) failedAgentNames.push("Scanner");
if (!isAnalystValid) failedAgentNames.push("Forensic Analyst");
if (!isDevilValid) failedAgentNames.push("Devil's Advocate");

const allAgentVotes = [];
if (isScannerValid) allAgentVotes.push(scannerVerdict.impression);
if (isAnalystValid) allAgentVotes.push(analystVerdict.classification);
if (isDevilValid) allAgentVotes.push(devilsAdvocateVerdict.counter_classification);

const voteCountsByClassification = {};
for (const vote of allAgentVotes) {
  voteCountsByClassification[vote] = (voteCountsByClassification[vote] || 0) + 1;
}

return [{
  json: {
    finalVerdict: {
      classification: finalClassification,
      confidence: finalConfidenceScore,
      weightedScore: Math.round(combinedWeightedScore * 100) / 100,
    },
    debate: {
      scanner: scannerVerdict,
      analyst: analystVerdict,
      devilsAdvocate: devilsAdvocateVerdict,
    },
    metrics: textMetrics,
    metricSignals: { ai: aiSignalCount, human: humanSignalCount },
    voteCounts: voteCountsByClassification,
    originalText: analystPackageOutput.originalText,
    failedAgents: failedAgentNames,
  }
}];

