// Packages the Scanner agent's raw output together with the original text and metrics so the next agent has full context.

const metricsNodeOutput = $('Extract Stylometric Metrics').first().json;
const scannerRawOutput = $input.first().json.output || $input.first().json.text || "";

let parsedScannerVerdict = {};

try {
  let cleanedScannerOutput = scannerRawOutput.trim();
  if (cleanedScannerOutput.startsWith("```json")) cleanedScannerOutput = cleanedScannerOutput.slice(7);
  if (cleanedScannerOutput.startsWith("```")) cleanedScannerOutput = cleanedScannerOutput.slice(3);
  if (cleanedScannerOutput.endsWith("```")) cleanedScannerOutput = cleanedScannerOutput.slice(0, -3);
  parsedScannerVerdict = JSON.parse(cleanedScannerOutput.trim());
} catch (parseError) {
  parsedScannerVerdict = {
    impression: "unknown",
    confidence: 0,
    gut_reasoning: "Scanner failed to produce valid output: " + parseError.message,
  };
}

return [{
  json: {
    originalText: metricsNodeOutput.originalText,
    metrics: metricsNodeOutput.metrics,
    scannerVerdict: parsedScannerVerdict,
  }
}];

// Grab the original text directly from the Chat Trigger node

const rawText = $('When chat message received').first().json.chatInput;


const tableRows = $input.all();


const aiFingerprintWordList = tableRows
  .map(row => row.json.word)
  .filter(word => word && word.trim().length > 0)
  .map(word => word.trim().toLowerCase());


const allSentences = rawText.split(/[.!?]+/).filter((sentence) => sentence.trim().length > 0);
const allWordsLowercase = rawText.toLowerCase().split(/\s+/).filter((word) => word.length > 0);
const uniqueWordSet = new Set(allWordsLowercase);

const sentenceLengthsInWords = allSentences.map((sentence) => sentence.trim().split(/\s+/).length);
const averageSentenceLength = sentenceLengthsInWords.reduce((sum, length) => sum + length, 0) / (sentenceLengthsInWords.length || 1);

const sentenceLengthVariance = sentenceLengthsInWords.reduce((sum, length) => {
  return sum + Math.pow(length - averageSentenceLength, 2);
}, 0) / (sentenceLengthsInWords.length || 1);

const burstinessScore = Math.sqrt(sentenceLengthVariance) / (averageSentenceLength || 1);

const typeTokenRatio = allWordsLowercase.length > 0 ? uniqueWordSet.size / allWordsLowercase.length : 0;

const wordFrequencyMap = {};
for (const word of allWordsLowercase) {
  wordFrequencyMap[word] = (wordFrequencyMap[word] || 0) + 1;
}
const wordsAppearingOnce = Object.values(wordFrequencyMap).filter((count) => count === 1).length;
const hapaxLegomenaRate = uniqueWordSet.size > 0 ? wordsAppearingOnce / uniqueWordSet.size : 0;

const allBigrams = [];
for (let i = 0; i < allWordsLowercase.length - 1; i++) {
  allBigrams.push(allWordsLowercase[i] + " " + allWordsLowercase[i + 1]);
}
const uniqueBigramSet = new Set(allBigrams);
const bigramRepetitionScore = allBigrams.length > 0 ? 1 - (uniqueBigramSet.size / allBigrams.length) : 0;

const allParagraphs = rawText.split(/\n\n+/).filter((paragraph) => paragraph.trim().length > 0);
const paragraphLengthsInWords = allParagraphs.map((paragraph) => paragraph.trim().split(/\s+/).length);
const averageParagraphLength = paragraphLengthsInWords.reduce((sum, length) => sum + length, 0) / (paragraphLengthsInWords.length || 1);
const paragraphLengthVariance = paragraphLengthsInWords.reduce((sum, length) => {
  return sum + Math.pow(length - averageParagraphLength, 2);
}, 0) / (paragraphLengthsInWords.length || 1);

const detectedFingerprintWords = [];
const fingerprintMatchCount = allWordsLowercase.filter((word) => {
  if (aiFingerprintWordList.includes(word)) {
    detectedFingerprintWords.push(word);
    return true;
  }
  return false;
}).length;
const fingerprintDensity = allWordsLowercase.length > 0 ? fingerprintMatchCount / allWordsLowercase.length : 0;

const extractedMetrics = {
  totalWords: allWordsLowercase.length,
  totalSentences: allSentences.length,
  totalParagraphs: allParagraphs.length,
  avgSentenceLength: Math.round(averageSentenceLength * 100) / 100,
  sentenceLengthVariance: Math.round(sentenceLengthVariance * 100) / 100,
  burstiness: Math.round(burstinessScore * 100) / 100,
  typeTokenRatio: Math.round(typeTokenRatio * 100) / 100,
  hapaxRate: Math.round(hapaxLegomenaRate * 100) / 100,
  repetitionScore: Math.round(bigramRepetitionScore * 100) / 100,
  avgParagraphLength: Math.round(averageParagraphLength * 100) / 100,
  paragraphVariance: Math.round(paragraphLengthVariance * 100) / 100,
  transitionDensity: Math.round(fingerprintDensity * 1000) / 1000,
  aiFingerprintsFound: detectedFingerprintWords,
  aiFingerprintCount: detectedFingerprintWords.length,
};

return [{
  json: {
    originalText: rawText,
    metrics: extractedMetrics,
  }
}];

// Collects all existing fingerprint words from the data table into a single comma-separated string for the LLM to reference.

const words = $input.all().map(item => item.json.word).filter(w => w);
return [{ json: { existingWords: words.join(', ') } }];

// Splits the LLM's comma-separated response into individual words and formats each as a separate row for saving to the data table.

const response = $input.first().json.text || $input.first().json.output || "";
const newWords = response.split(',').map(w => w.trim().toLowerCase()).filter(w => w.length > 0);

return newWords.map(word => ({
  json: { word: word }
}));
